public static String identityToString(final Object object) {
    if (object == null) {
        return null;
    }
    final String name = object.getClass().getName();
    final String hexString = identityHashCodeHex(object);
    final StringBuilder builder = new StringBuilder(name.length() + 1 + hexString.length());
    // @formatter:off
    builder.append(name)
          .append(AT_SIGN)
          .append(hexString);
    // @formatter:on
    return builder.toString();
}

public void start() {
    if (runningState == State.STOPPED) {
        throw new IllegalStateException("Stopwatch must be reset before being restarted.");
    }
    if (runningState != State.UNSTARTED) {
        throw new IllegalStateException("Stopwatch already started.");
    }
    startTimeNanos = System.nanoTime();
    startInstant = Instant.now();
    runningState = State.RUNNING;
    splits.clear();
}

public int elementCompareTo(final T element) {
    // Comparable API says throw NPE on null
    Objects.requireNonNull(element, "element");
    if (isAfter(element)) {
        return -1;
    }
    if (isBefore(element)) {
        return 1;
    }
    return 0;
}

@Override
    public <T> Invoker<T> select(List<Invoker<T>> invokers, URL url, Invocation invocation) {
        if (CollectionUtils.isEmpty(invokers)) {
            return null;
        }
        if (invokers.size() == 1) {
            return invokers.get(0);
        }
        return doSelect(invokers, url, invocation);
    }

    protected abstract <T> Invoker<T> doSelect(List<Invoker<T>> invokers, URL url, Invocation invocation);

public Collection<E> read(JsonReader in) throws IOException {
  if (in.peek() == JsonToken.NULL) {
    in.nextNull();
    return null;
  }

  Collection<E> collection = constructor.construct();
  in.beginArray();
  while (in.hasNext()) {
    E instance = elementTypeAdapter.read(in);
    collection.add(instance);
  }
  in.endArray();
  return collection;
}

static String separateCamelCase(String name, char separator) {
  StringBuilder translation = new StringBuilder();
  for (int i = 0, length = name.length(); i < length; i++) {
    char character = name.charAt(i);
    if (Character.isUpperCase(character) && translation.length() != 0) {
      translation.append(separator);
    }
    translation.append(character);
  }
  return translation.toString();
}

@Override
  public T read(JsonReader in) throws IOException {
    if (in.peek() == JsonToken.NULL) {
      in.nextNull();
      return null;
    }
    String key = in.nextString();
    T constant = nameToConstant.get(key);
    // Note: If none of the approaches find the constant, this returns null
    return (constant == null) ? stringToConstant.get(key) : constant;
  }

  @Override
  public void write(JsonWriter out, T value) throws IOException {
    out.value(value == null ? null : constantToName.get(value));
  }

private static Map<Class<?>, Object> primitiveDefaults() {
  Map<Class<?>, Object> zeroes = new HashMap<>();
  zeroes.put(byte.class, (byte) 0);
  zeroes.put(short.class, (short) 0);
  zeroes.put(int.class, 0);
  zeroes.put(long.class, 0L);
  zeroes.put(float.class, 0F);
  zeroes.put(double.class, 0D);
  zeroes.put(char.class, '\0');
  zeroes.put(boolean.class, false);
  return zeroes;
}

private int partition(int left, int right, int pivotIndex) {
  T pivotValue = uncheckedCastNullableTToT(buffer[pivotIndex]);
  buffer[pivotIndex] = buffer[right];

  int pivotNewIndex = left;
  for (int i = left; i < right; i++) {
    if (comparator.compare(uncheckedCastNullableTToT(buffer[i]), pivotValue) < 0) {
      swap(pivotNewIndex, i);
      pivotNewIndex++;
    }
  }
  buffer[right] = buffer[pivotNewIndex];
  buffer[pivotNewIndex] = pivotValue;
  return pivotNewIndex;
}

public boolean contains(ReadableInterval interval) {
    if (interval == null) {
        return containsNow();
    }
    long otherStart = interval.getStartMillis();
    long otherEnd = interval.getEndMillis();
    long thisStart = getStartMillis();
    long thisEnd = getEndMillis();
    return (thisStart <= otherStart && otherStart < thisEnd && otherEnd <= thisEnd);
}

public boolean overlaps(ReadableInterval interval) {
    long thisStart = getStartMillis();
    long thisEnd = getEndMillis();
    if (interval == null) {
        long now = DateTimeUtils.currentTimeMillis();
        return (thisStart < now && now < thisEnd);
    }  else {
        long otherStart = interval.getStartMillis();
        long otherEnd = interval.getEndMillis();
        return (thisStart < otherEnd && otherStart < thisEnd);
    }
}

private fun retryAfter(
  userResponse: Response,
  defaultDelay: Int,
): Int {
  val header = userResponse.header("Retry-After") ?: return defaultDelay

  // https://tools.ietf.org/html/rfc7231#section-7.1.3
  // currently ignores a HTTP-date, and assumes any non int 0 is a delay
  if (header.matches("\\d+".toRegex())) {
    return Integer.valueOf(header)
  }
  return Integer.MAX_VALUE
}

fun connectionBecameIdle(connection: RealConnection): Boolean {
  connection.assertLockHeld()

  return if (connection.noNewExchanges || maxIdleConnections == 0) {
    connection.noNewExchanges = true
    connections.remove(connection)
    if (connections.isEmpty()) cleanupQueue.cancelAll()
    true
  } else {
    scheduleCloser()
    false
  }
}

public static <T extends Comparable<? super T>> T min(final T... values) {
    T result = null;
    if (values != null) {
        for (final T value : values) {
            if (compare(value, result, true) < 0) {
                result = value;
            }
        }
    }
    return result;
}

public void split() {
    if (runningState != State.RUNNING) {
        throw new IllegalStateException("Stopwatch is not running.");
    }
    stopSet();
    splitState = SplitState.SPLIT;
    splits.add(new Split(String.valueOf(splits.size()), Duration.ofNanos(stopTimeNanos - startTimeNanos)));
}

public void stop() {
    if (runningState != State.RUNNING && runningState != State.SUSPENDED) {
        throw new IllegalStateException("Stopwatch is not running.");
    }
    if (runningState == State.RUNNING) {
        stopSet();
    }
    runningState = State.STOPPED;
}

public static <T extends Throwable> void accept(final FailableBiConsumer<Long, Integer, T> consumer, final Duration duration)
            throws T {
        if (consumer != null && duration != null) {
            consumer.accept(duration.toMillis(), getNanosOfMilli(duration));
        }
    }

public static long toMillisLong(final Duration duration) {
    Objects.requireNonNull(duration, "duration");
    try {
        return duration.toMillis();
    } catch (final ArithmeticException e) {
        return duration.isNegative() ? Long.MIN_VALUE : Long.MAX_VALUE;
    }
}

public T fit(final T element) {
    // Comparable API says throw NPE on null
    Objects.requireNonNull(element, "element");
    if (isAfter(element)) {
        return minimum;
    }
    if (isBefore(element)) {
        return maximum;
    }
    return element;
}

public boolean equals(final Object obj) {
    if (obj == this) {
        return true;
    }
    if (obj == null || obj.getClass() != getClass()) {
        return false;
    }
    @SuppressWarnings("unchecked") // OK because we checked the class above
    final
    Range<T> range = (Range<T>) obj;
    return minimum.equals(range.minimum) &&
           maximum.equals(range.maximum);
}

AbstractRetryTask(URL url, FailbackRegistry registry, String taskName) {
    if (url == null || StringUtils.isBlank(taskName)) {
        throw new IllegalArgumentException();
    }
    this.url = url;
    this.registry = registry;
    this.taskName = taskName;
    this.cancel = false;
    this.retryPeriod = url.getParameter(REGISTRY_RETRY_PERIOD_KEY, DEFAULT_REGISTRY_RETRY_PERIOD);
    this.retryTimes = url.getParameter(REGISTRY_RETRY_TIMES_KEY, DEFAULT_REGISTRY_RETRY_TIMES);
}

public Set<String> getLoadedExtensions() {
    return Collections.unmodifiableSet(new TreeSet<>(cachedInstances.keySet()));
}

