public static final Chronology getIntervalChronology(ReadableInstant start, ReadableInstant end) {
    Chronology chrono = null;
    if (start != null) {
        chrono = start.getChronology();
    } else if (end != null) {
        chrono = end.getChronology();
    }
    if (chrono == null) {
        chrono = ISOChronology.getInstance();
    }
    return chrono;
}

@Override
    public boolean equals(Object readableInstant) {
        // must be to fulfil ReadableInstant contract
        if (this == readableInstant) {
            return true;
        }
        if (readableInstant instanceof ReadableInstant == false) {
            return false;
        }
        ReadableInstant otherInstant = (ReadableInstant) readableInstant;
        return
            getMillis() == otherInstant.getMillis() &&
            FieldUtils.equals(getChronology(), otherInstant.getChronology());
    }

public boolean equals(Object readableInterval) {
    if (this == readableInterval) {
        return true;
    }
    if (readableInterval instanceof ReadableInterval == false) {
        return false;
    }
    ReadableInterval other = (ReadableInterval) readableInterval;
    return
        getStartMillis() == other.getStartMillis() &&
        getEndMillis() == other.getEndMillis() &&
        FieldUtils.equals(getChronology(), other.getChronology());
}

private void checkAndUpdate(DurationFieldType type, int[] values, int newValue) {
    int index = indexOf(type);
    if (index == -1) {
        if (newValue != 0) {
            throw new IllegalArgumentException(
                "Period does not support field '" + type.getName() + "'");
        }
    } else {
        values[index] = newValue;
    }
}

public DateTime withFieldAdded(DurationFieldType fieldType, int amount) {
    if (fieldType == null) {
        throw new IllegalArgumentException("Field must not be null");
    }
    if (amount == 0) {
        return this;
    }
    long instant = fieldType.getField(getChronology()).add(getMillis(), amount);
    return withMillis(instant);
}

@Override
    protected DateTimeField getField(int index, Chronology chrono) {
        switch (index) {
            case YEAR:
                return chrono.year();
            case MONTH_OF_YEAR:
                return chrono.monthOfYear();
            case DAY_OF_MONTH:
                return chrono.dayOfMonth();
            default:
                throw new IndexOutOfBoundsException("Invalid index: " + index);
        }
    }

public boolean hasPrefix(UniqueId potentialPrefix) {
	Preconditions.notNull(potentialPrefix, "potentialPrefix must not be null");
	int size = this.segments.size();
	int prefixSize = potentialPrefix.segments.size();
	return size >= prefixSize && this.segments.subList(0, prefixSize).equals(potentialPrefix.segments);
}

public static boolean isValid(@Nullable String name) {
	if (name == null) {
		return false;
	}
	name = name.strip();

	return !name.isEmpty() && //
			StringUtils.doesNotContainWhitespace(name) && //
			StringUtils.doesNotContainIsoControlCharacter(name) && //
			doesNotContainReservedCharacter(name);
}

public UniqueId append(Segment segment) {
	Preconditions.notNull(segment, "segment must not be null");
	List<Segment> baseSegments = new ArrayList<>(this.segments.size() + 1);
	baseSegments.addAll(this.segments);
	baseSegments.add(segment);
	return new UniqueId(baseSegments);
}

protected void deallocate() {
    FileChannel file = this.file;

    if (file == null) {
        return;
    }
    this.file = null;

    try {
        file.close();
    } catch (IOException e) {
        logger.warn("Failed to close a file.", e);
    }
}

override fun execute(): Response {
  check(executed.compareAndSet(false, true)) { "Already Executed" }

  timeout.enter()
  callStart()
  try {
    client.dispatcher.executed(this)
    return getResponseWithInterceptorChain()
  } finally {
    client.dispatcher.finished(this)
  }
}

static boolean isAnnotationPresent(Annotation[] annotations, Class<? extends Annotation> cls) {
  for (Annotation annotation : annotations) {
    if (cls.isInstance(annotation)) {
      return true;
    }
  }
  return false;
}

static ResponseBody buffer(final ResponseBody body) throws IOException {
  Buffer buffer = new Buffer();
  body.source().readAll(buffer);
  return ResponseBody.create(body.contentType(), body.contentLength(), buffer);
}

public static byte CONST_BYTE(final int v) {
    if (v < Byte.MIN_VALUE || v > Byte.MAX_VALUE) {
        throw new IllegalArgumentException("Supplied value must be a valid byte literal between -128 and 127: [" + v + "]");
    }
    return (byte) v;
}

public static short CONST_SHORT(final int v) {
    if (v < Short.MIN_VALUE || v > Short.MAX_VALUE) {
        throw new IllegalArgumentException("Supplied value must be a valid byte literal between -32768 and 32767: [" + v + "]");
    }
    return (short) v;
}

public static <T extends Comparable<? super T>> T max(final T... values) {
    T result = null;
    if (values != null) {
        for (final T value : values) {
            if (compare(value, result, false) > 0) {
                result = value;
            }
        }
    }
    return result;
}

@Override
  public String toString() {
    try {
      StringBuilder stringBuilder = new StringBuilder();
      JsonWriter jsonWriter = new JsonWriter(Streams.writerForAppendable(stringBuilder));
      // Make writer lenient because toString() must not fail, even if for example JsonPrimitive
      // contains NaN
      jsonWriter.setStrictness(Strictness.LENIENT);
      Streams.write(this, jsonWriter);
      return stringBuilder.toString();
    } catch (IOException e) {
      throw new AssertionError(e);
    }
  }

public String toString() {
  long nanos = elapsedNanos();

  TimeUnit unit = chooseUnit(nanos);
  double value = (double) nanos / NANOSECONDS.convert(1, unit);

  // Too bad this functionality is not exposed as a regular method call
  return Platform.formatCompact4Digits(value) + " " + abbreviate(unit);
}

static Pattern compileIsoControlPattern() {
	// https://docs.oracle.com/en/java/javase/17/docs/api/java.base/java/util/regex/Pattern.html#posix
	try {
		// All of the characters that Unicode refers to as 'control characters'
		return Pattern.compile("\\p{Cntrl}", UNICODE_CHARACTER_CLASS);
	}
	catch (IllegalArgumentException e) {
		// Fall-back to ASCII control characters only: [\x00-\x1F\x7F]
		return Pattern.compile("\\p{Cntrl}");
	}
}

public static <T> Stream<DynamicTest> stream(Stream<? extends Named<T>> inputStream,
			ThrowingConsumer<? super T> testExecutor) {
		Preconditions.notNull(inputStream, "inputStream must not be null");
		Preconditions.notNull(testExecutor, "testExecutor must not be null");

		return inputStream //
				.map(input -> dynamicTest(input.getName(), () -> testExecutor.accept(input.getPayload())));
	}

private static boolean includesJunitStart(List<StackTraceElement> stackTrace, int fromIndex) {
	return stackTrace.stream() //
			.skip(fromIndex) //
			.map(StackTraceElement::getClassName) //
			.anyMatch(className -> className.startsWith(JUNIT_START_PACKAGE_PREFIX));
}

private fun shouldIgnoreAndWaitForRealResponse(code: Int): Boolean =
    when {
      // Server sent a 100-continue even though we did not request one. Try again to read the
      // actual response status.
      code == 100 -> true

      // Handle Processing (102) & Early Hints (103) and any new codes without failing
      // 100 and 101 are the exceptions with different meanings
      // But Early Hints not currently exposed
      code in (102 until 200) -> true

      else -> false
    }
